#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a[10004],ans=0;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    while(1){
        int tmp=ans;
        for(int i=1;i<=n;i++)
            if(a[i]!=i)swap(a[i],a[a[i]]),ans++;
        if(tmp==ans)break;
    }
    cout<<ans;
    return 0;
}
